-- LET Reviewer PH — Question Bank Batch 2 (Questions 201-400)

INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES

-- GENERAL EDUCATION: ENGLISH (201-260)
('General Education','English - Grammar','easy','Which sentence has correct subject-verb agreement?','[{"key":"A","text":"The group of students are noisy."},{"key":"B","text":"Each of the boys have a pencil."},{"key":"C","text":"Neither of them is ready."},{"key":"D","text":"The news are alarming."}]','C','Neither/either takes a singular verb. "Neither of them is ready" is correct.','both'),

('General Education','English - Grammar','medium','Choose the sentence in the passive voice.','[{"key":"A","text":"Maria wrote the letter."},{"key":"B","text":"The letter was written by Maria."},{"key":"C","text":"Maria is writing the letter."},{"key":"D","text":"Maria will write the letter."}]','B','Passive voice uses "to be" + past participle. "The letter was written by Maria" is passive.','both'),

('General Education','English - Grammar','easy','Which word is an adjective in the sentence: "The bright student answered quickly"?','[{"key":"A","text":"student"},{"key":"B","text":"answered"},{"key":"C","text":"bright"},{"key":"D","text":"quickly"}]','C','"Bright" modifies the noun "student" and is therefore an adjective.','both'),

('General Education','English - Grammar','medium','Which sentence uses the correct pronoun?','[{"key":"A","text":"Between you and I, this is wrong."},{"key":"B","text":"He gave the award to Maria and I."},{"key":"C","text":"The winner was her."},{"key":"D","text":"Him and I went to school."}]','C','"The winner was her" uses the objective pronoun correctly as a predicate nominative in casual English. "Between you and me" is correct (not I).','both'),

('General Education','English - Grammar','easy','The word "quickly" in "She ran quickly" is a/an:','[{"key":"A","text":"Adjective"},{"key":"B","text":"Noun"},{"key":"C","text":"Adverb"},{"key":"D","text":"Preposition"}]','C','"Quickly" modifies the verb "ran" and is an adverb.','both'),

('General Education','English - Grammar','medium','Which sentence uses the past perfect tense correctly?','[{"key":"A","text":"She had already eaten when I arrived."},{"key":"B","text":"She already ate when I arrived."},{"key":"C","text":"She has eaten when I arrive."},{"key":"D","text":"She was eating when I arrived."}]','A','Past perfect (had + past participle) expresses an action completed before another past action.','both'),

('General Education','English - Grammar','medium','Identify the figure of speech: "The wind whispered through the trees."','[{"key":"A","text":"Simile"},{"key":"B","text":"Hyperbole"},{"key":"C","text":"Personification"},{"key":"D","text":"Metaphor"}]','C','Personification gives human qualities (whispering) to a non-human thing (wind).','both'),

('General Education','English - Grammar','easy','A simile uses which words to make a comparison?','[{"key":"A","text":"is, are, was"},{"key":"B","text":"like or as"},{"key":"C","text":"because, since"},{"key":"D","text":"and, but, or"}]','B','Similes explicitly compare using "like" or "as": "brave as a lion," "runs like the wind."','both'),

('General Education','English - Grammar','medium','Which is an example of a metaphor?','[{"key":"A","text":"She is as tall as a tree."},{"key":"B","text":"Life is a journey."},{"key":"C","text":"The wind howled all night."},{"key":"D","text":"He ate a mountain of food."}]','B','A metaphor directly equates two things without "like" or "as": "Life is a journey."','both'),

('General Education','English - Grammar','medium','Choose the correctly punctuated sentence.','[{"key":"A","text":"However I disagree with you."},{"key":"B","text":"However, I disagree with you."},{"key":"C","text":"However I, disagree with you."},{"key":"D","text":"However I disagree, with you."}]','B','Introductory conjunctive adverbs like "however" are followed by a comma.','both'),

('General Education','English - Reading','medium','The main idea of a paragraph is usually found in the:','[{"key":"A","text":"Last sentence"},{"key":"B","text":"Middle sentence"},{"key":"C","text":"Topic sentence (often the first sentence)"},{"key":"D","text":"Supporting details"}]','C','The topic sentence, usually at the beginning, states the main idea that the rest of the paragraph supports.','both'),

('General Education','English - Reading','medium','An inference is:','[{"key":"A","text":"A direct statement from the text"},{"key":"B","text":"A conclusion drawn from evidence and reasoning"},{"key":"C","text":"The author''s biography"},{"key":"D","text":"The definition of a word"}]','B','Inference requires reading between the lines — using clues to draw conclusions not explicitly stated.','both'),

('General Education','English - Reading','easy','The SQ3R reading strategy stands for:','[{"key":"A","text":"Scan, Question, Read, Review, Respond"},{"key":"B","text":"Survey, Question, Read, Recite, Review"},{"key":"C","text":"Skim, Query, Read, Reread, Reflect"},{"key":"D","text":"Study, Question, Read, Report, Revise"}]','B','SQ3R: Survey, Question, Read, Recite, Review — a systematic study-reading strategy.','both'),

('General Education','English - Reading','medium','Context clues help readers:','[{"key":"A","text":"Memorize vocabulary lists"},{"key":"B","text":"Determine word meanings from surrounding text"},{"key":"C","text":"Identify the author''s name"},{"key":"D","text":"Count syllables in words"}]','B','Context clues are words and phrases surrounding an unfamiliar word that help determine its meaning.','both'),

('General Education','English - Literature','medium','José Rizal''s "Noli Me Tangere" was written in:','[{"key":"A","text":"Filipino"},{"key":"B","text":"English"},{"key":"C","text":"Spanish"},{"key":"D","text":"Latin"}]','C','Rizal wrote Noli Me Tangere in Spanish in 1887 to expose the injustices of Spanish colonial rule.','both'),

('General Education','English - Literature','medium','Which literary work by Rizal was published second?','[{"key":"A","text":"Noli Me Tangere"},{"key":"B","text":"El Filibusterismo"},{"key":"C","text":"Mi Ultimo Adios"},{"key":"D","text":"Sobre la Indolencia"}]','B','El Filibusterismo (1891) was the sequel to Noli Me Tangere (1887).','both'),

('General Education','English - Literature','easy','The plot element that introduces the main conflict is called the:','[{"key":"A","text":"Resolution"},{"key":"B","text":"Climax"},{"key":"C","text":"Rising action"},{"key":"D","text":"Exposition"}]','D','The exposition (or introduction) establishes setting, characters, and the initial situation/conflict.','both'),

('General Education','English - Literature','medium','The climax of a story is:','[{"key":"A","text":"The introduction of characters"},{"key":"B","text":"The highest point of tension or turning point"},{"key":"C","text":"The final resolution of the conflict"},{"key":"D","text":"The background information"}]','B','The climax is the moment of greatest tension or the turning point in the narrative.','both'),

('General Education','English - Literature','easy','Which genre uses verse, rhythm, and imagery to express emotions or ideas?','[{"key":"A","text":"Novel"},{"key":"B","text":"Drama"},{"key":"C","text":"Poetry"},{"key":"D","text":"Essay"}]','C','Poetry is characterized by rhythmic language, imagery, and condensed expression of emotions and ideas.','both'),

('General Education','English - Literature','medium','A flat character in fiction is one who:','[{"key":"A","text":"Changes significantly throughout the story"},{"key":"B","text":"Remains unchanged and is described with limited traits"},{"key":"C","text":"Is always the protagonist"},{"key":"D","text":"Is physically described in great detail"}]','B','Flat characters have simple, unchanging traits and serve a limited narrative function.','both'),

('General Education','English - Writing','easy','The thesis statement in an essay:','[{"key":"A","text":"Provides supporting evidence"},{"key":"B","text":"States the main argument or central claim"},{"key":"C","text":"Concludes the discussion"},{"key":"D","text":"Lists the essay''s sources"}]','B','The thesis statement presents the writer''s central claim or argument that the essay will support and develop.','both'),

('General Education','English - Writing','medium','Coherence in writing means:','[{"key":"A","text":"Using long, complex sentences"},{"key":"B","text":"Ideas flow logically and are clearly connected"},{"key":"C","text":"Using many transition words"},{"key":"D","text":"Writing exactly 500 words"}]','B','Coherence means all parts of a piece of writing connect logically, making it easy for readers to follow.','both'),

('General Education','English - Writing','easy','Which transition word shows contrast?','[{"key":"A","text":"Furthermore"},{"key":"B","text":"Therefore"},{"key":"C","text":"However"},{"key":"D","text":"In addition"}]','C','"However" signals a contrast or contradiction with the previous idea.','both'),

('General Education','English - Writing','medium','Denotation is a word''s:','[{"key":"A","text":"Emotional or cultural association"},{"key":"B","text":"Literal, dictionary meaning"},{"key":"C","text":"Sound when spoken"},{"key":"D","text":"Origin or etymology"}]','B','Denotation is the precise, literal meaning of a word as found in a dictionary.','both'),

('General Education','English - Writing','medium','Connotation refers to:','[{"key":"A","text":"A word''s literal meaning"},{"key":"B","text":"The emotional or cultural meaning associated with a word"},{"key":"C","text":"The grammatical function of a word"},{"key":"D","text":"The number of syllables in a word"}]','B','Connotation is the implied or emotional meaning of a word beyond its literal definition (e.g., "home" vs. "house").','both'),

('General Education','English - Grammar','medium','Which sentence contains a dangling modifier?','[{"key":"A","text":"Running fast, John won the race."},{"key":"B","text":"Running fast, the finish line was crossed."},{"key":"C","text":"John, running fast, won the race."},{"key":"D","text":"The race was won by John who ran fast."}]','B','"Running fast" has no clear subject to modify in "the finish line was crossed" — it is a dangling modifier.','both'),

('General Education','English - Grammar','easy','A conjunction connects:','[{"key":"A","text":"A noun to a verb"},{"key":"B","text":"Words, phrases, or clauses"},{"key":"C","text":"An adjective to a noun"},{"key":"D","text":"A verb to its object"}]','B','Conjunctions (and, but, because, although) link words, phrases, and clauses together.','both'),

('General Education','English - Grammar','medium','The sentence "He is the man who fixed the car" contains a:','[{"key":"A","text":"Noun phrase"},{"key":"B","text":"Adjective clause"},{"key":"C","text":"Adverb clause"},{"key":"D","text":"Noun clause"}]','B','The relative clause "who fixed the car" modifies the noun "man" and is therefore an adjective (relative) clause.','both'),

('General Education','English - Grammar','medium','A hyperbole is:','[{"key":"A","text":"A direct comparison using like or as"},{"key":"B","text":"An extreme exaggeration for emphasis"},{"key":"C","text":"Giving human traits to objects"},{"key":"D","text":"A contradiction that reveals truth"}]','B','Hyperbole uses extreme exaggeration: "I''ve told you a million times" emphasizes frequency.','both'),

('General Education','English - Grammar','hard','Which sentence uses a gerund correctly?','[{"key":"A","text":"She enjoys to swim in the morning."},{"key":"B","text":"Swimming is her favorite activity."},{"key":"C","text":"She swim every morning."},{"key":"D","text":"She has swum yesterday."}]','B','A gerund is a verb ending in -ing used as a noun. "Swimming" functions as the subject here.','both'),

('General Education','English - Reading','medium','An author''s purpose in writing can be to:','[{"key":"A","text":"Entertain, inform, or persuade"},{"key":"B","text":"Confuse, distract, or amuse"},{"key":"C","text":"Test, grade, or evaluate readers"},{"key":"D","text":"Copy, plagiarize, or misquote"}]','A','Authors write to entertain (stories), inform (articles), or persuade (editorials/arguments).','both'),

('General Education','English - Literature','medium','Which literary device uses a reference to a well-known person, place, or event?','[{"key":"A","text":"Alliteration"},{"key":"B","text":"Allusion"},{"key":"C","text":"Assonance"},{"key":"D","text":"Allegory"}]','B','Allusion is a reference to a famous work, person, or event: "He was a real Romeo with the ladies."','both'),

('General Education','English - Grammar','easy','The plural of "child" is:','[{"key":"A","text":"Childs"},{"key":"B","text":"Childrens"},{"key":"C","text":"Children"},{"key":"D","text":"Childes"}]','C','"Children" is the irregular plural form of "child."','both'),

('General Education','English - Grammar','medium','Which is a compound sentence?','[{"key":"A","text":"Because she was tired, she slept."},{"key":"B","text":"She was tired and she slept."},{"key":"C","text":"She slept."},{"key":"D","text":"Tired from work, she slept."}]','B','A compound sentence joins two independent clauses with a coordinating conjunction (and, but, or, so).','both'),

('General Education','English - Literature','medium','The theme of a literary work is:','[{"key":"A","text":"The sequence of events in the story"},{"key":"B","text":"The central message or insight about life"},{"key":"C","text":"The main character''s name"},{"key":"D","text":"The setting of the story"}]','B','Theme is the universal message or insight about human experience that runs through the work.','both'),

('General Education','English - Grammar','easy','In indirect speech, "She said, I am tired" becomes:','[{"key":"A","text":"She said that she is tired."},{"key":"B","text":"She said that she was tired."},{"key":"C","text":"She said that I am tired."},{"key":"D","text":"She said that she are tired."}]','B','In reported (indirect) speech, the present tense shifts to past: "am" → "was."','both'),

('General Education','English - Reading','hard','Critical reading requires the reader to:','[{"key":"A","text":"Accept all information as factual"},{"key":"B","text":"Analyze, evaluate, and question the text"},{"key":"C","text":"Read quickly without pausing"},{"key":"D","text":"Focus only on unfamiliar words"}]','B','Critical reading involves active evaluation of the text''s arguments, evidence, assumptions, and biases.','both'),

('General Education','English - Grammar','medium','Onomatopoeia refers to:','[{"key":"A","text":"Words that imitate the sounds they describe"},{"key":"B","text":"Repetition of consonant sounds"},{"key":"C","text":"Comparing two unlike things"},{"key":"D","text":"Exaggeration for emphasis"}]','A','Onomatopoeia uses words that phonetically imitate natural sounds: buzz, hiss, crack, splash.','both'),

('General Education','English - Writing','medium','In an argumentative essay, a counterargument is used to:','[{"key":"A","text":"Weaken the writer''s own position"},{"key":"B","text":"Acknowledge opposing views and then refute them"},{"key":"C","text":"Copy another writer''s ideas"},{"key":"D","text":"Replace the thesis statement"}]','B','Addressing counterarguments and refuting them strengthens the writer''s credibility and argument.','both'),

('General Education','English - Grammar','easy','An antonym of "abundant" is:','[{"key":"A","text":"Plentiful"},{"key":"B","text":"Scarce"},{"key":"C","text":"Ample"},{"key":"D","text":"Generous"}]','B','"Scarce" means in short supply — the opposite of "abundant" (plentiful, in large quantities).','both'),

('General Education','English - Grammar','medium','Which sentence uses a comma correctly?','[{"key":"A","text":"I went to the market and I bought vegetables."},{"key":"B","text":"I went to the market, and I bought vegetables."},{"key":"C","text":"I went to the market and, I bought vegetables."},{"key":"D","text":"I went, to the market and I bought vegetables."}]','B','A comma precedes a coordinating conjunction (FANBOYS) when joining two independent clauses.','both'),

('General Education','English - Grammar','medium','The word "although" is a:','[{"key":"A","text":"Coordinating conjunction"},{"key":"B","text":"Subordinating conjunction"},{"key":"C","text":"Conjunctive adverb"},{"key":"D","text":"Preposition"}]','B','"Although" is a subordinating conjunction introducing a dependent (adverb) clause.','both'),

('General Education','English - Literature','easy','The narrator of "Noli Me Tangere" who observes events from outside is a/an:','[{"key":"A","text":"First-person narrator"},{"key":"B","text":"Third-person omniscient narrator"},{"key":"C","text":"Second-person narrator"},{"key":"D","text":"Unreliable narrator"}]','B','Rizal uses a third-person omniscient narrator who knows all characters'' thoughts and feelings.','both'),

('General Education','English - Grammar','hard','A sentence with a dependent and independent clause is a:','[{"key":"A","text":"Simple sentence"},{"key":"B","text":"Compound sentence"},{"key":"C","text":"Complex sentence"},{"key":"D","text":"Compound-complex sentence"}]','C','A complex sentence contains one independent clause and at least one dependent (subordinate) clause.','both'),

('General Education','English - Grammar','easy','The prefix "un-" in "unhappy" means:','[{"key":"A","text":"Very"},{"key":"B","text":"Not"},{"key":"C","text":"Again"},{"key":"D","text":"Before"}]','B','The prefix "un-" negates the root word: unhappy = not happy, unlikely = not likely.','both'),

-- GENERAL EDUCATION: MATHEMATICS (261-320)
('General Education','Mathematics - Arithmetic','easy','What is 15% of 200?','[{"key":"A","text":"25"},{"key":"B","text":"30"},{"key":"C","text":"35"},{"key":"D","text":"40"}]','B','15% of 200 = 0.15 × 200 = 30.','both'),

('General Education','Mathematics - Arithmetic','easy','What is the value of 3² + 4²?','[{"key":"A","text":"25"},{"key":"B","text":"14"},{"key":"C","text":"49"},{"key":"D","text":"7"}]','A','3² + 4² = 9 + 16 = 25. (Note: This also illustrates the Pythagorean triple 3-4-5.)','both'),

('General Education','Mathematics - Arithmetic','easy','What is the LCM of 4 and 6?','[{"key":"A","text":"2"},{"key":"B","text":"8"},{"key":"C","text":"12"},{"key":"D","text":"24"}]','C','LCM(4,6) = 12. The smallest number divisible by both 4 and 6.','both'),

('General Education','Mathematics - Arithmetic','easy','What is the GCF of 18 and 24?','[{"key":"A","text":"3"},{"key":"B","text":"6"},{"key":"C","text":"9"},{"key":"D","text":"12"}]','B','GCF(18,24) = 6. Factors of 18: 1,2,3,6,9,18; Factors of 24: 1,2,3,4,6,8,12,24. Greatest common: 6.','both'),

('General Education','Mathematics - Arithmetic','medium','A shirt costs ₱450. If the price is increased by 20%, the new price is:','[{"key":"A","text":"₱490"},{"key":"B","text":"₱510"},{"key":"C","text":"₱540"},{"key":"D","text":"₱560"}]','C','Increase = 20% × ₱450 = ₱90. New price = ₱450 + ₱90 = ₱540.','both'),

('General Education','Mathematics - Arithmetic','medium','The ratio of boys to girls in a class is 3:2. If there are 30 students, how many are boys?','[{"key":"A","text":"12"},{"key":"B","text":"15"},{"key":"C","text":"18"},{"key":"D","text":"20"}]','C','Total parts = 5. Boys = (3/5) × 30 = 18.','both'),

('General Education','Mathematics - Arithmetic','easy','What is ⅔ + ¾?','[{"key":"A","text":"5/6"},{"key":"B","text":"17/12"},{"key":"C","text":"5/12"},{"key":"D","text":"7/12"}]','B','⅔ + ¾ = 8/12 + 9/12 = 17/12.','both'),

('General Education','Mathematics - Arithmetic','medium','A car travels 120 km in 2 hours. What is its average speed?','[{"key":"A","text":"40 kph"},{"key":"B","text":"50 kph"},{"key":"C","text":"60 kph"},{"key":"D","text":"70 kph"}]','C','Speed = Distance ÷ Time = 120 ÷ 2 = 60 kph.','both'),

('General Education','Mathematics - Arithmetic','medium','Two workers can complete a job in 6 hours. One worker alone takes 10 hours. How many hours does the other take alone?','[{"key":"A","text":"12"},{"key":"B","text":"14"},{"key":"C","text":"15"},{"key":"D","text":"16"}]','C','Combined rate = 1/6. Worker A rate = 1/10. Worker B = 1/6 - 1/10 = 5/30 - 3/30 = 2/30 = 1/15. B takes 15 hours.','both'),

('General Education','Mathematics - Arithmetic','easy','If a is 25% of b, then b is what percent of a?','[{"key":"A","text":"75%"},{"key":"B","text":"200%"},{"key":"C","text":"400%"},{"key":"D","text":"300%"}]','C','If a = 0.25b, then b = 4a, so b is 400% of a.','both'),

('General Education','Mathematics - Algebra','medium','Solve for x: 3x + 7 = 22','[{"key":"A","text":"3"},{"key":"B","text":"5"},{"key":"C","text":"7"},{"key":"D","text":"9"}]','B','3x = 22 - 7 = 15; x = 15/3 = 5.','both'),

('General Education','Mathematics - Algebra','medium','What is the slope of the line passing through (2, 3) and (4, 7)?','[{"key":"A","text":"1"},{"key":"B","text":"2"},{"key":"C","text":"3"},{"key":"D","text":"4"}]','B','Slope = (7-3)/(4-2) = 4/2 = 2.','both'),

('General Education','Mathematics - Algebra','medium','Solve the system: x + y = 7 and x - y = 3','[{"key":"A","text":"x=4, y=3"},{"key":"B","text":"x=5, y=2"},{"key":"C","text":"x=6, y=1"},{"key":"D","text":"x=3, y=4"}]','B','Adding equations: 2x = 10, x = 5. Substituting: 5 + y = 7, y = 2.','both'),

('General Education','Mathematics - Algebra','medium','The quadratic formula solves ax² + bx + c = 0. What is x?','[{"key":"A","text":"x = (-b ± √(b²+4ac)) / 2a"},{"key":"B","text":"x = (-b ± √(b²-4ac)) / 2a"},{"key":"C","text":"x = (b ± √(b²-4ac)) / 2a"},{"key":"D","text":"x = (-b ± √(b²-4ac)) / a"}]','B','The quadratic formula is x = (-b ± √(b²-4ac)) / 2a.','both'),

('General Education','Mathematics - Algebra','easy','What is the value of 2³ × 2²?','[{"key":"A","text":"2⁴"},{"key":"B","text":"2⁵"},{"key":"C","text":"2⁶"},{"key":"D","text":"4⁵"}]','B','When multiplying same bases, add exponents: 2³ × 2² = 2^(3+2) = 2⁵ = 32.','both'),

('General Education','Mathematics - Algebra','medium','Factor completely: x² - 9','[{"key":"A","text":"(x-3)(x-3)"},{"key":"B","text":"(x+3)(x-3)"},{"key":"C","text":"(x+9)(x-1)"},{"key":"D","text":"x(x-9)"}]','B','x² - 9 is a difference of squares: (x+3)(x-3).','both'),

('General Education','Mathematics - Algebra','medium','If f(x) = 2x + 3, what is f(4)?','[{"key":"A","text":"8"},{"key":"B","text":"10"},{"key":"C","text":"11"},{"key":"D","text":"14"}]','C','f(4) = 2(4) + 3 = 8 + 3 = 11.','both'),

('General Education','Mathematics - Algebra','hard','The age problem: Father is 4 times as old as his son. In 8 years, the father will be twice the son''s age. How old is the son now?','[{"key":"A","text":"8"},{"key":"B","text":"10"},{"key":"C","text":"12"},{"key":"D","text":"16"}]','A','Let son = x, father = 4x. In 8 years: 4x+8 = 2(x+8). 4x+8 = 2x+16. 2x = 8. x = 8 (son is 8).','both'),

('General Education','Mathematics - Geometry','easy','The sum of angles in a triangle is:','[{"key":"A","text":"90°"},{"key":"B","text":"180°"},{"key":"C","text":"270°"},{"key":"D","text":"360°"}]','B','The interior angles of any triangle always sum to 180°.','both'),

('General Education','Mathematics - Geometry','easy','The Pythagorean theorem states that in a right triangle: a² + b² = c², where c is the:','[{"key":"A","text":"Shortest side"},{"key":"B","text":"Longest side (hypotenuse)"},{"key":"C","text":"Height of the triangle"},{"key":"D","text":"Base of the triangle"}]','B','The hypotenuse (c) is the side opposite the right angle and is always the longest side.','both'),

('General Education','Mathematics - Geometry','medium','A right triangle has legs of 6 and 8. What is the hypotenuse?','[{"key":"A","text":"10"},{"key":"B","text":"12"},{"key":"C","text":"14"},{"key":"D","text":"100"}]','A','c² = 6² + 8² = 36 + 64 = 100. c = √100 = 10.','both'),

('General Education','Mathematics - Geometry','easy','The area of a circle with radius 7 is (use π ≈ 22/7):','[{"key":"A","text":"44"},{"key":"B","text":"154"},{"key":"C","text":"22"},{"key":"D","text":"196"}]','B','Area = πr² = (22/7)(7²) = (22/7)(49) = 154 sq. units.','both'),

('General Education','Mathematics - Geometry','easy','The perimeter of a rectangle 8 cm long and 5 cm wide is:','[{"key":"A","text":"13 cm"},{"key":"B","text":"26 cm"},{"key":"C","text":"40 cm"},{"key":"D","text":"80 cm"}]','B','Perimeter = 2(l + w) = 2(8 + 5) = 2(13) = 26 cm.','both'),

('General Education','Mathematics - Geometry','medium','The volume of a rectangular box 5 cm × 4 cm × 3 cm is:','[{"key":"A","text":"12 cm³"},{"key":"B","text":"47 cm³"},{"key":"C","text":"60 cm³"},{"key":"D","text":"120 cm³"}]','C','Volume = l × w × h = 5 × 4 × 3 = 60 cm³.','both'),

('General Education','Mathematics - Geometry','medium','Two parallel lines cut by a transversal form alternate interior angles that are:','[{"key":"A","text":"Supplementary"},{"key":"B","text":"Complementary"},{"key":"C","text":"Equal (congruent)"},{"key":"D","text":"Right angles"}]','C','Alternate interior angles formed by parallel lines and a transversal are always congruent.','both'),

('General Education','Mathematics - Statistics','easy','The mean of 5, 10, 15, 20, 25 is:','[{"key":"A","text":"10"},{"key":"B","text":"15"},{"key":"C","text":"20"},{"key":"D","text":"25"}]','B','Mean = (5+10+15+20+25)/5 = 75/5 = 15.','both'),

('General Education','Mathematics - Statistics','easy','The median of 3, 5, 7, 9, 11 is:','[{"key":"A","text":"5"},{"key":"B","text":"7"},{"key":"C","text":"9"},{"key":"D","text":"11"}]','B','The median is the middle value of an ordered set. With 5 values, the middle (3rd) value is 7.','both'),

('General Education','Mathematics - Statistics','easy','The mode of 2, 3, 3, 4, 5, 3, 6 is:','[{"key":"A","text":"2"},{"key":"B","text":"3"},{"key":"C","text":"4"},{"key":"D","text":"5"}]','B','The mode is the most frequently occurring value. 3 appears three times.','both'),

('General Education','Mathematics - Statistics','medium','The probability of rolling an even number on a standard die is:','[{"key":"A","text":"1/6"},{"key":"B","text":"1/3"},{"key":"C","text":"1/2"},{"key":"D","text":"2/3"}]','C','Even numbers on a die: 2, 4, 6 = 3 outcomes out of 6. P = 3/6 = 1/2.','both'),

('General Education','Mathematics - Statistics','medium','In a class of 40 students, a test has a mean of 75 and standard deviation of 5. A student scores 85. How many standard deviations above the mean is this score?','[{"key":"A","text":"1"},{"key":"B","text":"2"},{"key":"C","text":"3"},{"key":"D","text":"4"}]','B','z = (85 - 75) / 5 = 10/5 = 2 standard deviations above the mean.','both'),

('General Education','Mathematics - Algebra','medium','Simplify: (3x²y)(4xy³)','[{"key":"A","text":"7x³y⁴"},{"key":"B","text":"12x³y⁴"},{"key":"C","text":"12x²y³"},{"key":"D","text":"7x²y³"}]','B','Multiply coefficients: 3×4=12. Add exponents of x: 2+1=3. Add exponents of y: 1+3=4. Result: 12x³y⁴.','both'),

('General Education','Mathematics - Arithmetic','medium','A mixture of 10 liters contains 30% alcohol. How many liters of alcohol are there?','[{"key":"A","text":"2"},{"key":"B","text":"3"},{"key":"C","text":"4"},{"key":"D","text":"5"}]','B','30% of 10 = 0.30 × 10 = 3 liters of alcohol.','both'),

('General Education','Mathematics - Arithmetic','medium','Train A travels at 60 kph and Train B at 90 kph. They leave the same station in opposite directions. After 2 hours, how far apart are they?','[{"key":"A","text":"120 km"},{"key":"B","text":"150 km"},{"key":"C","text":"300 km"},{"key":"D","text":"180 km"}]','C','Distance = (60+90) × 2 = 150 × 2 = 300 km.','both'),

('General Education','Mathematics - Statistics','medium','In how many ways can 5 students be arranged in a row?','[{"key":"A","text":"25"},{"key":"B","text":"60"},{"key":"C","text":"120"},{"key":"D","text":"150"}]','C','5! = 5 × 4 × 3 × 2 × 1 = 120 arrangements.','both'),

('General Education','Mathematics - Statistics','medium','From a group of 5 people, how many combinations of 2 can be formed?','[{"key":"A","text":"5"},{"key":"B","text":"10"},{"key":"C","text":"15"},{"key":"D","text":"20"}]','B','C(5,2) = 5!/(2!3!) = (5×4)/(2×1) = 10 combinations.','both'),

('General Education','Mathematics - Algebra','easy','What is the next term in the sequence 2, 5, 8, 11, ...?','[{"key":"A","text":"12"},{"key":"B","text":"13"},{"key":"C","text":"14"},{"key":"D","text":"15"}]','C','This is an arithmetic sequence with common difference 3. Next term = 11 + 3 = 14.','both'),

('General Education','Mathematics - Algebra','medium','The sum of the first 10 terms of the arithmetic sequence 1, 3, 5, 7... is:','[{"key":"A","text":"55"},{"key":"B","text":"100"},{"key":"C","text":"90"},{"key":"D","text":"50"}]','B','S = n/2 × (first + last). Last term = 1 + 9(2) = 19. S = 10/2 × (1+19) = 5 × 20 = 100.','both'),

('General Education','Mathematics - Geometry','medium','The area of a trapezoid with parallel sides 8 and 12, and height 5 is:','[{"key":"A","text":"40"},{"key":"B","text":"50"},{"key":"C","text":"100"},{"key":"D","text":"60"}]','B','Area = ½(b₁ + b₂)h = ½(8+12)(5) = ½(20)(5) = 50 sq. units.','both'),

('General Education','Mathematics - Arithmetic','hard','Batch A can fill a tank in 4 hours, batch B in 6 hours. Working together, how long to fill the tank?','[{"key":"A","text":"2 hours"},{"key":"B","text":"2.4 hours"},{"key":"C","text":"3 hours"},{"key":"D","text":"5 hours"}]','B','Combined rate = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 per hour. Time = 12/5 = 2.4 hours.','both'),

('General Education','Mathematics - Geometry','medium','An isosceles triangle has two equal sides. If the vertex angle is 40°, what is each base angle?','[{"key":"A","text":"60°"},{"key":"B","text":"70°"},{"key":"C","text":"80°"},{"key":"D","text":"90°"}]','B','Sum of angles = 180°. Base angles = (180° - 40°)/2 = 140°/2 = 70°.','both'),

('General Education','Mathematics - Statistics','medium','Two dice are rolled. What is the probability of getting a sum of 7?','[{"key":"A","text":"1/6"},{"key":"B","text":"1/9"},{"key":"C","text":"5/36"},{"key":"D","text":"7/36"}]','A','Favorable outcomes for sum 7: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6. Total = 36. P = 6/36 = 1/6.','both'),

-- GENERAL EDUCATION: SCIENCE (321-380)
('General Education','Science - Biology','easy','The basic unit of life is the:','[{"key":"A","text":"Tissue"},{"key":"B","text":"Organ"},{"key":"C","text":"Cell"},{"key":"D","text":"Atom"}]','C','The cell is the smallest structural and functional unit of all living organisms.','both'),

('General Education','Science - Biology','medium','Photosynthesis converts:','[{"key":"A","text":"Oxygen and water into glucose and carbon dioxide"},{"key":"B","text":"Carbon dioxide and water into glucose and oxygen"},{"key":"C","text":"Glucose and oxygen into carbon dioxide and water"},{"key":"D","text":"Nitrogen and water into proteins"}]','B','Photosynthesis: 6CO₂ + 6H₂O + light → C₆H₁₂O₆ + 6O₂. Plants convert CO₂ and H₂O into glucose and oxygen.','both'),

('General Education','Science - Biology','easy','The powerhouse of the cell is the:','[{"key":"A","text":"Nucleus"},{"key":"B","text":"Ribosome"},{"key":"C","text":"Mitochondria"},{"key":"D","text":"Chloroplast"}]','C','Mitochondria produce ATP (energy) through cellular respiration — earning the title "powerhouse of the cell."','both'),

('General Education','Science - Biology','medium','DNA is found primarily in the cell''s:','[{"key":"A","text":"Cytoplasm"},{"key":"B","text":"Nucleus"},{"key":"C","text":"Ribosome"},{"key":"D","text":"Cell membrane"}]','B','The nucleus contains the cell''s DNA, organized into chromosomes that carry genetic information.','both'),

('General Education','Science - Biology','medium','Mitosis results in:','[{"key":"A","text":"2 genetically identical daughter cells"},{"key":"B","text":"4 genetically diverse daughter cells"},{"key":"C","text":"2 cells with half the chromosome number"},{"key":"D","text":"1 cell with double chromosomes"}]','A','Mitosis is cell division for growth and repair, producing 2 identical cells with the same chromosome number as the parent.','both'),

('General Education','Science - Biology','medium','Meiosis produces:','[{"key":"A","text":"2 identical diploid cells"},{"key":"B","text":"4 genetically unique haploid cells"},{"key":"C","text":"2 haploid cells"},{"key":"D","text":"4 identical diploid cells"}]','B','Meiosis produces 4 genetically unique haploid (23 chromosomes in humans) sex cells (gametes).','both'),

('General Education','Science - Biology','easy','According to Mendel, a trait that is masked in the presence of a dominant trait is:','[{"key":"A","text":"Dominant"},{"key":"B","text":"Recessive"},{"key":"C","text":"Co-dominant"},{"key":"D","text":"Incomplete dominant"}]','B','Recessive traits are only expressed when two copies of the recessive allele are present (homozygous recessive).','both'),

('General Education','Science - Biology','medium','Darwin''s theory of evolution by natural selection states that:','[{"key":"A","text":"All species were created simultaneously"},{"key":"B","text":"Organisms with favorable traits survive and reproduce more successfully"},{"key":"C","text":"Evolution is always directed toward complexity"},{"key":"D","text":"Traits acquired during life are inherited"}]','B','Natural selection: organisms with traits better suited to their environment survive, reproduce, and pass traits to offspring.','both'),

('General Education','Science - Biology','medium','Which organelle is responsible for protein synthesis?','[{"key":"A","text":"Mitochondria"},{"key":"B","text":"Golgi apparatus"},{"key":"C","text":"Ribosome"},{"key":"D","text":"Vacuole"}]','C','Ribosomes are the sites of protein synthesis, translating mRNA sequences into amino acid chains.','both'),

('General Education','Science - Biology','easy','The process by which plants make food using sunlight is called:','[{"key":"A","text":"Respiration"},{"key":"B","text":"Transpiration"},{"key":"C","text":"Photosynthesis"},{"key":"D","text":"Fermentation"}]','C','Photosynthesis is the process by which plants use light energy to convert CO₂ and water into glucose.','both'),

('General Education','Science - Biology','medium','A food chain correctly shows:','[{"key":"A","text":"Decomposer → Producer → Consumer"},{"key":"B","text":"Consumer → Producer → Decomposer"},{"key":"C","text":"Producer → Primary Consumer → Secondary Consumer"},{"key":"D","text":"Carnivore → Herbivore → Plant"}]','C','Energy flows from producers (plants) to primary consumers (herbivores) to secondary consumers (carnivores).','both'),

('General Education','Science - Chemistry','easy','Matter is anything that:','[{"key":"A","text":"Can be seen with the naked eye"},{"key":"B","text":"Has mass and occupies space"},{"key":"C","text":"Is in solid form"},{"key":"D","text":"Can be chemically changed"}]','B','Matter is defined as anything that has mass and occupies space (volume).','both'),

('General Education','Science - Chemistry','medium','A physical change differs from a chemical change because:','[{"key":"A","text":"Physical changes produce new substances"},{"key":"B","text":"Physical changes are irreversible"},{"key":"C","text":"Physical changes do not produce new substances"},{"key":"D","text":"Chemical changes only involve color changes"}]','C','Physical changes alter form but not composition (melting, cutting); chemical changes produce new substances (burning, rusting).','both'),

('General Education','Science - Chemistry','easy','The pH scale measures:','[{"key":"A","text":"Temperature of a solution"},{"key":"B","text":"Acidity or basicity of a solution"},{"key":"C","text":"Electrical conductivity"},{"key":"D","text":"Density of liquids"}]','B','The pH scale (0–14) measures acidity (0–6), neutrality (7), and basicity/alkalinity (8–14).','both'),

('General Education','Science - Chemistry','medium','An acid has a pH:','[{"key":"A","text":"Greater than 7"},{"key":"B","text":"Equal to 7"},{"key":"C","text":"Less than 7"},{"key":"D","text":"Greater than 14"}]','C','Acids have pH less than 7; bases have pH greater than 7; neutral substances have pH of exactly 7.','both'),

('General Education','Science - Chemistry','medium','Atoms of the same element but different mass numbers are called:','[{"key":"A","text":"Ions"},{"key":"B","text":"Isotopes"},{"key":"C","text":"Allotropes"},{"key":"D","text":"Compounds"}]','B','Isotopes have the same number of protons (same element) but different numbers of neutrons (different mass numbers).','both'),

('General Education','Science - Chemistry','easy','A mixture can be separated by physical means because:','[{"key":"A","text":"Components have formed new substances"},{"key":"B","text":"Components retain their individual properties"},{"key":"C","text":"Components are chemically bonded"},{"key":"D","text":"Components are identical"}]','B','In a mixture, substances are physically combined and retain their individual properties; no chemical bonds form.','both'),

('General Education','Science - Physics','easy','Newton''s First Law of Motion states that:','[{"key":"A","text":"Force equals mass times acceleration"},{"key":"B","text":"Every action has an equal and opposite reaction"},{"key":"C","text":"An object at rest stays at rest unless acted upon by an external force"},{"key":"D","text":"Objects fall at the same rate regardless of mass"}]','C','Newton''s First Law (Law of Inertia): an object maintains its state of rest or uniform motion unless a net external force acts on it.','both'),

('General Education','Science - Physics','easy','Newton''s Second Law: F = ma means:','[{"key":"A","text":"Force equals mass minus acceleration"},{"key":"B","text":"Force is inversely proportional to mass"},{"key":"C","text":"Force equals mass times acceleration"},{"key":"D","text":"Mass equals force times acceleration"}]','C','F = ma: the net force on an object equals its mass multiplied by its acceleration.','both'),

('General Education','Science - Physics','medium','Newton''s Third Law states that:','[{"key":"A","text":"Objects accelerate toward Earth at 9.8 m/s²"},{"key":"B","text":"For every action, there is an equal and opposite reaction"},{"key":"C","text":"Energy cannot be created or destroyed"},{"key":"D","text":"Velocity increases with time"}]','B','Newton''s Third Law: forces always come in pairs — when object A exerts force on B, B exerts an equal and opposite force on A.','both'),

('General Education','Science - Physics','medium','The Law of Conservation of Energy states:','[{"key":"A","text":"Energy can be created from matter"},{"key":"B","text":"Energy can be destroyed but not created"},{"key":"C","text":"Energy cannot be created or destroyed, only transformed"},{"key":"D","text":"All energy eventually becomes heat"}]','C','Energy is conserved — it changes from one form to another (kinetic to potential, chemical to electrical) but is never created or destroyed.','both'),

('General Education','Science - Physics','easy','Sound travels fastest through:','[{"key":"A","text":"Vacuum"},{"key":"B","text":"Air"},{"key":"C","text":"Water"},{"key":"D","text":"Steel"}]','D','Sound travels fastest through solids (steel ≈ 5,100 m/s) > liquids > gases > cannot travel through vacuum.','both'),

('General Education','Science - Physics','medium','An object moving in a circular path experiences centripetal force directed:','[{"key":"A","text":"Away from the center"},{"key":"B","text":"Toward the center"},{"key":"C","text":"Tangentially to the path"},{"key":"D","text":"Downward due to gravity"}]','B','Centripetal force points toward the center of the circular path, keeping the object in circular motion.','both'),

('General Education','Science - Earth Science','easy','The Earth''s layers from surface to center are:','[{"key":"A","text":"Crust, mantle, outer core, inner core"},{"key":"B","text":"Crust, core, mantle, inner mantle"},{"key":"C","text":"Mantle, crust, outer core, inner core"},{"key":"D","text":"Crust, outer core, mantle, inner core"}]','A','Earth''s layers: crust (outermost), mantle, outer core (liquid), inner core (solid iron-nickel).','both'),

('General Education','Science - Earth Science','medium','The theory of plate tectonics explains:','[{"key":"A","text":"The age of the universe"},{"key":"B","text":"The movement of Earth''s lithospheric plates causing earthquakes and volcanoes"},{"key":"C","text":"The formation of clouds"},{"key":"D","text":"The reason for seasons"}]','B','Plate tectonics describes how Earth''s plates move, collide, and separate, causing earthquakes, volcanoes, and mountain formation.','both'),

('General Education','Science - Earth Science','easy','The water cycle includes which processes?','[{"key":"A","text":"Evaporation, condensation, precipitation, collection"},{"key":"B","text":"Photosynthesis, respiration, fermentation"},{"key":"C","text":"Erosion, deposition, weathering"},{"key":"D","text":"Convection, conduction, radiation"}]','A','The water cycle: evaporation (water → vapor), condensation (vapor → clouds), precipitation (rain/snow), and collection.','both'),

('General Education','Science - Earth Science','medium','The Philippines is located in the Pacific Ring of Fire, which means it is prone to:','[{"key":"A","text":"Hurricanes and typhoons only"},{"key":"B","text":"Earthquakes and volcanic eruptions"},{"key":"C","text":"Extreme cold and snowfall"},{"key":"D","text":"Flooding from river systems"}]','B','The Ring of Fire is a zone of frequent earthquakes and volcanic eruptions surrounding the Pacific Ocean; the Philippines sits on this ring.','both'),

('General Education','Science - Biology','medium','Which human body system is responsible for transporting oxygen to cells?','[{"key":"A","text":"Digestive system"},{"key":"B","text":"Nervous system"},{"key":"C","text":"Circulatory system"},{"key":"D","text":"Skeletal system"}]','C','The circulatory system (heart, blood vessels, blood) transports oxygen, nutrients, and hormones to cells throughout the body.','both'),

('General Education','Science - Biology','easy','The organ responsible for gas exchange (oxygen in, carbon dioxide out) in humans is the:','[{"key":"A","text":"Heart"},{"key":"B","text":"Liver"},{"key":"C","text":"Kidneys"},{"key":"D","text":"Lungs"}]','D','The lungs are the site of gas exchange: oxygen moves into the blood, and carbon dioxide moves out.','both'),

('General Education','Science - Chemistry','medium','Covalent bonds are formed by:','[{"key":"A","text":"Transfer of electrons between atoms"},{"key":"B","text":"Sharing of electrons between atoms"},{"key":"C","text":"Attraction between oppositely charged ions"},{"key":"D","text":"Hydrogen bonding"}]','B','Covalent bonds form when atoms share one or more pairs of electrons; common in molecules like water (H₂O) and methane (CH₄).','both'),

('General Education','Science - Biology','medium','The role of the liver in digestion includes:','[{"key":"A","text":"Producing insulin for blood sugar regulation"},{"key":"B","text":"Producing bile to emulsify fats"},{"key":"C","text":"Absorbing water from digested food"},{"key":"D","text":"Producing hydrochloric acid for protein digestion"}]','B','The liver produces bile, which is stored in the gallbladder and released into the small intestine to emulsify (break up) fats.','both'),

-- SOCIAL STUDIES (381-400)
('General Education','Social Studies - Philippine History','easy','José Rizal was executed at Bagumbayan (now Luneta) on:','[{"key":"A","text":"June 12, 1898"},{"key":"B","text":"December 30, 1896"},{"key":"C","text":"August 23, 1896"},{"key":"D","text":"September 24, 1872"}]','B','Rizal was executed by firing squad on December 30, 1896, now commemorated as Rizal Day.','both'),

('General Education','Social Studies - Philippine History','easy','The Philippine Declaration of Independence was proclaimed on:','[{"key":"A","text":"June 12, 1898"},{"key":"B","text":"July 4, 1946"},{"key":"C","text":"February 25, 1986"},{"key":"D","text":"August 23, 1896"}]','A','Philippine Independence was declared on June 12, 1898 in Kawit, Cavite by General Emilio Aguinaldo.','both'),

('General Education','Social Studies - Philippine History','medium','The Katipunan was founded by:','[{"key":"A","text":"José Rizal"},{"key":"B","text":"Emilio Aguinaldo"},{"key":"C","text":"Andrés Bonifacio"},{"key":"D","text":"Apolinario Mabini"}]','C','Andrés Bonifacio founded the Kataastaasang Kagalanggalangang Katipunan (KKK) on July 7, 1892.','both'),

('General Education','Social Studies - Philippine History','medium','The EDSA People Power Revolution in 1986 resulted in:','[{"key":"A","text":"The end of American colonization"},{"key":"B","text":"The fall of Ferdinand Marcos and rise of Corazon Aquino"},{"key":"C","text":"Philippine independence from Spain"},{"key":"D","text":"The founding of the Katipunan"}]','B','The February 1986 EDSA Revolution ended the Marcos dictatorship and installed Corazon Aquino as president.','both'),

('General Education','Social Studies - Philippine Government','easy','The 1987 Philippine Constitution established which form of government?','[{"key":"A","text":"Parliamentary"},{"key":"B","text":"Federal"},{"key":"C","text":"Presidential-Unitary"},{"key":"D","text":"Monarchical"}]','C','The Philippines has a presidential form of government with a unitary structure, as established by the 1987 Constitution.','both'),

('General Education','Social Studies - Philippine Government','medium','The Philippine Senate is composed of how many senators?','[{"key":"A","text":"12"},{"key":"B","text":"24"},{"key":"C","text":"300"},{"key":"D","text":"50"}]','B','The Philippine Senate has 24 senators elected at large for 6-year terms.','both'),

('General Education','Social Studies - Economics','medium','Inflation refers to:','[{"key":"A","text":"A decrease in the general price level"},{"key":"B","text":"A sustained increase in the general price level"},{"key":"C","text":"The growth rate of GDP"},{"key":"D","text":"The rate of unemployment"}]','B','Inflation is a general and sustained rise in the price level of goods and services in an economy.','both'),

('General Education','Social Studies - Economics','easy','Supply and demand law states that when demand increases and supply stays the same:','[{"key":"A","text":"Prices fall"},{"key":"B","text":"Prices rise"},{"key":"C","text":"Prices stay the same"},{"key":"D","text":"Production stops"}]','B','When demand rises and supply is constant, competition among buyers drives prices upward.','both'),

('General Education','Social Studies - World History','medium','World War II ended in Europe on V-E Day (Victory in Europe Day):','[{"key":"A","text":"August 15, 1945"},{"key":"B","text":"May 8, 1945"},{"key":"C","text":"June 6, 1944"},{"key":"D","text":"September 2, 1945"}]','B','V-E Day (May 8, 1945) marked Germany''s unconditional surrender; V-J Day (August 15) marked Japan''s surrender.','both'),

('General Education','Social Studies - Geography','easy','The Philippines is an archipelago comprising approximately how many islands?','[{"key":"A","text":"3,000"},{"key":"B","text":"5,000"},{"key":"C","text":"7,641"},{"key":"D","text":"10,000"}]','C','The Philippines consists of approximately 7,641 islands, divided into three main island groups: Luzon, Visayas, and Mindanao.','both'),

('General Education','Social Studies - Philippine History','medium','Martial Law in the Philippines was declared by President Ferdinand Marcos on:','[{"key":"A","text":"September 21, 1972"},{"key":"B","text":"February 25, 1986"},{"key":"C","text":"August 21, 1983"},{"key":"D","text":"June 12, 1898"}]','A','Marcos declared Martial Law on September 21, 1972, suspending civil rights and press freedom.','both');
